{
var src = inputs.Length > 0 ? inputs[0] : null;
if (src == null)
    return new PixelBuffer(context.TileSize, context.TileSize);

var angleDeg = GetFloat(parameters, "angle", 0f);
var distance = GetFloat(parameters, "distance", 10f);
var quality = GetInt(parameters, "quality", 8);

var angleRad = angleDeg * MathF.PI / 180f;
var cosA = MathF.Cos(angleRad);
var sinA = MathF.Sin(angleRad);

var size = src.Width;
var result = new PixelBuffer(size, size);

var samples = Math.Max(2, quality);

result.ParallelForEachPixel((x, y) =>
{
    var sumR = 0f; var sumG = 0f; var sumB = 0f; var sumA = 0f;

    for (var i = 0; i < samples; i++)
    {
        var t = (i / (float)(samples - 1)) - 0.5f;
        var sx = x + cosA * t * distance;
        var sy = y + sinA * t * distance;
        var (pr, pg, pb, pa) = src.GetPixelWrapped((int)MathF.Round(sx), (int)MathF.Round(sy));
        sumR += pr; sumG += pg; sumB += pb; sumA += pa;
    }

    var inv = 1f / samples;
    result.SetPixel(x, y, sumR * inv, sumG * inv, sumB * inv, sumA * inv);
});

return result;
}
